KET_RISK_EXPOSURES.V_SELL_PAY_CCY_CODE,to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY) FROM ( SELECT FCT_MARKET_RISK_EXPOSURES.* ,'EXP_' || FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY || '_' || ROW_NUMBER() OVER ( PARTITION BY FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY ORDER BY FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY ) V_EXPOSURE_ID ,FCT_UNDERLYING_DTL.D_ISSUE_DATE D_ISSUE_DATE_ULY ,FCT_UNDERLYING_DTL.D_MATURITY_DATE D_MATURITY_DATE_ULY ,FCT_UNDERLYING_DTL.N_CONTRACT_ACCT_SKEY N_CONTRACT_ACCT_SKEY_ULY ,FCT_UNDERLYING_DTL.N_CTD_CONVERSION_FACTOR N_CTD_CONVERSION_FACTOR_ULY ,FCT_UNDERLYING_DTL.N_CURR_MKT_VALUE N_CURR_MKT_VALUE_ULY ,FCT_UNDERLYING_DTL.N_INSTRUMENT_SKEY N_INSTRUMENT_SKEY_ULY ,FCT_UNDERLYING_DTL.N_ISSUE_SKEY N_ISSUE_SKEY_ULY ,FCT_UNDERLYING_DTL.N_MR_ISSUER_TYPE_SKEY N_MR_ISSUER_TYPE_SKEY_ULY ,FCT_UNDERLYING_DTL.N_OUTSTANDING_UNITS N_OUTSTANDING_UNITS_ULY ,FCT_UNDERLYING_DTL.N_PAR_VALUE N_PAR_VALUE_ULY ,FCT_UNDERLYING_DTL.N_WEIGHTED_FUT_VALUE N_WEIGHTED_FUT_VALUE_ULY ,FCT_UNDERLYING_DTL.V_DAY_COUNTER V_DAY_COUNTER_ULY ,FCT_UNDERLYING_DTL.N_COUPON N_COUPON_ULY ,FCT_UNDERLYING_DTL.N_COUPON_FREQ N_COUPON_FREQ_ULY FROM FCT_UNDERLYING_DTL INNER JOIN DIM_DATES ON FCT_UNDERLYING_DTL.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND FCT_UNDERLYING_DTL.N_RUN_SKEY = '870' INNER JOIN FCT_MARKET_RISK_EXPOSURES ON FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY = FCT_UNDERLYING_DTL.N_CONTRACT_ACCT_SKEY AND FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY = FCT_UNDERLYING_DTL.N_RUN_SKEY AND FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY = FCT_UNDERLYING_DTL.N_MIS_DATE_SKEY ) FCT_MARKET_RISK_EXPOSURES INNER JOIN DIM_DATES ON FCT_MARKET_RISK_EXPOSURES.n_mis_date_skey = Dim_Dates.n_Date_Skey AND DIM_DATES.d_Calendar_Date = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON FCT_MARKET_RISK_EXPOSURES.n_run_skey = DIM_RUN.n_run_skey AND FCT_MARKET_RISK_EXPOSURES.n_run_skey = '870' INNER JOIN DIM_EXPOSURE ON DIM_EXPOSURE.V_EXPOSURE_ID = FCT_MARKET_RISK_EXPOSURES.V_EXPOSURE_ID AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN DIM_INSTRUMENT_TYPE ON FCT_MARKET_RISK_EXPOSURES.n_instr_type_skey = DIM_INSTRUMENT_TYPE.n_instr_type_skey INNER JOIN DIM_MARKET_RISK_POSITION ON FCT_MARKET_RISK_EXPOSURES.n_position_skey = DIM_MARKET_RISK_POSITION.n_position_skey LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'MR' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE WHERE 1=1 AND 1=1 AND DIM_INSTRUMENT_TYPE.v_instr_type_code = 'IRFUTSBFUT' LOG ERRORS INTO FCT_MARKET_RISK_EXPOSURES$ ('1776768592658_46555002_20260331_1_Job_3eaa08f073bc4fb0876920d5d1a8a6b5') REJECT LIMIT 0;

